-fg-muted, #64748b); }.surface__chat[data-v-ad14ed25] { display: flex; flex-direction: column; flex: 1 1 auto; min-width: 0px; min-height: 0px; }.surface__transcript[data-v-ad14ed25] { flex: 1 1 auto; min-height: 0px; }.surface__done-note[data-v-ad14ed25] { padding: 0.6rem 1.1rem; font-size: 0.8rem; color: var(--k-fg-muted, #64748b); background: var(--k-bg-widget, #14171d); border-top: 1px solid var(--k-border-subtle, #2a2f3a); text-align: center; }.surface__error[data-v-ad14ed25] { padding: 0.5rem 1.1rem; font-size: 0.78rem; color: var(--k-error, #fca5a5); }.surface__thinking[data-v-ad14ed25] { display: flex; align-items: flex-start; gap: 10px; padding: 8px 24px 0px; max-width: 98%; }.surface__thinking-avatar[data-v-ad14ed25] { flex: 0 0 auto; width: 32px; height: 32px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 13px; font-weight: 600; color: rgb(255, 255, 255); background: var(--k-fg-subtle, #475569); user-select: none; }.surface__thinking-bubble[data-v-ad14ed25] { background: var(--k-paper-bg, #f7f8fa); color: var(--k-paper-fg, #1f2430); border: 1px solid var(--k-paper-border, #d8dbe2); border-radius: 12px 12px 12px 4px; padding: 10px 14px; font-size: 14px; line-height: 1.5; min-width: 120px; max-width: 100%; overflow-wrap: anywhere; }.surface__thinking-role[data-v-ad14ed25] { font-size: 11px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.04em; opacity: 0.6; margin-bottom: 4px; }.surface__thinking-dots[data-v-ad14ed25] { display: flex; gap: 4px; font-size: 20px; color: var(--k-fg-muted, #94a3b8); }@keyframes surface-dot-pulse-ad14ed25 { 
  0%, 80%, 100% { opacity: 0.2; }
  40% { opacity: 1; }
}.surface__thinking-dots span[data-v-ad14ed25]:nth-child(1) { animation: 1.4s ease 0s infinite normal none running surface-dot-pulse-ad14ed25; }.surface__thinking-dots span[data-v-ad14ed25]:nth-child(2) { animation: 1.4s ease 0.2s infinite normal none running surface-dot-pulse-ad14ed25; }.surface__thinking-dots span[data-v-ad14ed25]:nth-child(3) { animation: 1.4s ease 0.4s infinite normal none running surface-dot-pulse-ad14ed25; }

